from flask import Flask, request, jsonify, redirect
from werkzeug.security import generate_password_hash, check_password_hash
import secrets
import string
import time
from datetime import datetime

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

# In-memory storage for authorization codes and tokens
auth_codes = {}
access_tokens = {}
clients = {
    "test_client": {
        "client_id": "test_client",
        "client_secret": generate_password_hash("test_secret"),
        "redirect_uris": ["http://localhost:5000/callback"]
    }
}

def generate_auth_code():
    return ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(32))

def generate_access_token():
    return secrets.token_urlsafe(32)

def validate_client(client_id, client_secret):
    if client_id not in clients:
        return False
    return check_password_hash(clients[client_id]["client_secret"], client_secret)

def validate_redirect_uri(client_id, redirect_uri):
    return redirect_uri in clients[client_id]["redirect_uris"]

@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    state = request.args.get('state')
    
    if not all([client_id, redirect_uri, response_type]):
        return jsonify({"error": "Invalid request parameters"}), 400
    
    if response_type != 'code':
        return jsonify({"error": "Unsupported response type"}), 400
    
    if not validate_redirect_uri(client_id, redirect_uri):
        return jsonify({"error": "Invalid redirect URI"}), 400
    
    # For demo purposes, we'll assume user is logged in
    user_id = "demo_user"
    
    auth_code = generate_auth_code()
    auth_codes[auth_code] = user_id
    
    redirect_url = f"{redirect_uri}?code={auth_code}"
    if state:
        redirect_url += f"&state={state}"
    
    return redirect(redirect_url)

@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    code = request.form.get('code')
    
    if not all([grant_type, client_id, client_secret]):
        return jsonify({"error": "Missing required parameters"}), 400
    
    if grant_type != 'authorization_code':
        return jsonify({"error": "Unsupported grant type"}), 400
    
    if not validate_client(client_id, client_secret):
        return jsonify({"error": "Invalid client credentials"}), 401
    
    if code not in auth_codes:
        return jsonify({"error": "Invalid authorization code"}), 400
    
    user_id = auth_codes[code]
    
    # Generate access token
    access_token = generate_access_token()
    access_tokens[access_token] = {
        "user_id": user_id,
        "expires_at": time.time() + 3600  # 1 hour expiry
    }
    
    # Remove used authorization code (for demo, we allow reuse for retry resilience)
    # In production, you might want to remove it after first use
    # del auth_codes[code]
    
    return jsonify({
        "access_token": access_token,
        "token_type": "Bearer",
        "expires_in": 3600
    })

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)